// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "17:40。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區。禮堂後方。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在二樓連廊的柱子後面。雨從連廊的簷口滴下來，在欄杆外面形成一道水簾。透過水簾，他能看見裝卸區的全貌——白色的校務廂型車停在月台邊，後門大開，裡面堆著直播備份器材箱和成捲的線材。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一名校安拿著板夾在車尾核對清單。兩名穿雨衣的學生志工正把最後幾箱設備推上車。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）校務車。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二章。我混上過這輛車。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有下去。許星棠站在連廊另一頭的樓梯口，背靠牆，相機掛在脖子上，攝影背心的口袋鼓了一塊——裡面塞著今天拍的素材。她的視線也在車上。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "被攔了。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音很低。不是在對顧言說。更像在陳述一個她早就知道的事實。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校安把板夾翻了一頁，對著車廂裡的設備指了指，又指了指清單上的某一行。學生志工停下來，從車廂裡搬出一個箱子，打開讓校安檢查。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）攔截線。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是命運。不是死亡修正力。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是有人在用安全檢查的名義，攔下這條線上所有可能帶走證據的東西。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）17:40，他在指揮室處理閉幕前的家長投訴。每一輪都是。這十五分鐘，他不看監控。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校安檢查完，揮手放行。學生志工把箱子推回去，關上後門。校安在板夾上簽了什麼，轉身往裝卸區側門走。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車沒有翻。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二章那場事故——車在後山路滑失控翻覆——是因為顧言藏在車廂裡，器材位移砸中司機，暴雨和後山路況疊加。這一輪，車廂裡沒有顧言。器材固定好了。司機沒有被突發聲響驚嚇。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攔截線仍存在。車仍被檢查、被延誤。但少了那些變數，它沒有失控成死亡。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是命運要殺我。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是攔截行動、暴雨、器材位移、司機受驚、後山路況——疊加在一起，才變成死亡。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）少了任何一環，攔截線還在，但不會死人。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校務車的引擎發動了。車燈在雨裡亮起來，兩道黃光穿過水霧。車緩緩駛離裝卸區，拐向後山方向。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著車尾燈消失在轉角，轉頭看了顧言一眼。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "真相機不在那條線上。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "走吧。19:30 拆展。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身往樓梯口走。腳步聲很輕，踩在積水上幾乎沒有聲音。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二章回收了。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是避開死亡。是看懂了死亡的結構。", background: Background.Chapter_8_Ch8_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他跟上去。雨從背後打過來，校服的肩膀又濕了一層。", background: Background.Chapter_8_Ch8_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:30。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "閉館了。展覽開始拆除。玻璃櫃的鎖被逐一打開，工作人員戴著白手套把展品取出，放進防震箱。地上散著氣泡紙和封箱膠帶。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有進去。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在校史館側門外的走廊上，隔著半開的鐵門往裡看。他的位置在展板拆除區的後方——一堆已經拆下來的展板靠牆疊著，剛好擋住他的身形。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠已經在裡面了。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在暫存區旁邊，相機掛在脖子上，藍色工作證別在攝影背心胸口。她的身份是校慶文檔組攝影——拆展時在場記錄，完全合理。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在基座另一側。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他穿著舞台組的深色外套，脖子上的藍底白字通行證晃來晃去。他蹲在基座的搬運輪組旁邊，手裡拿著一支手電筒，正在檢查輪子的固定螺絲。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "基座在房間正中央。百年時間膠囊展示基座。壓克力罩已經拆掉了，露出裡面的底板。底板是深色的，邊緣有金屬封條。這就是第四章和第六章顧言查過的東西——底板暗槽裡藏著十年前的工程付款紀錄備份。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任站在基座旁邊。深灰色西裝，金屬細框眼鏡，頭髮梳得很整齊。但比前幾輪——他更緊張了。他的手背在身後，但顧言看得出來，那雙手在抖。不是大幅度的抖。是手指在微微顫動，像在壓住什麼。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而且他不只是一個人。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "基座旁邊多了一個人。穿行政組背心的。年紀不大，手裡拿著板夾，站在基座的另一側，像在監看搬運流程。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）多了一個人。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前幾輪沒有。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任比之前更怕了。他加了一個人看著基座。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越站起來。他拍了拍輪組上的灰，轉向那名行政組人員。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "這組輪子。搬基座的時候走哪條動線？", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音不大。但穿透力強。像在問一件很正常的事，又像在命令對方回答。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Staff, character: "行政組人員", dialogue: "走側門。走廊夠寬。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "側門那邊坡度夠嗎。基座將近兩百公斤，輪子卡住了誰負責。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他蹲回去，用手電筒照了照輪組的軸承，然後站起來，往側門方向走了幾步，回頭。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我先確認動線。你等一下。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Staff, character: "行政組人員", dialogue: "⋯⋯好。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "行政組人員猶豫了一下，跟著往側門方向走了兩步。他的視線離開了基座。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這兩步。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠動了。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從暫存區旁邊走到基座側面。動作不快。不慢。像在拍拆展紀錄照一樣自然。她舉起相機——不是對著展品。是對著底板。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "快門聲很輕。在拆展的嘈雜裡，像一滴水落進水裡。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拍了底板暗槽的邊緣。金屬封條被動過的痕跡——有一道細細的刮痕，不是出廠時的，是後來被人用工具撬過的。林主任的痕跡。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二張。暗槽內側。付款紀錄影印件的邊角，從暗槽的縫隙裡露出一角。泛黃的紙。藍色印章。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三張。工程材料更換單。壓在付款紀錄下面，只露出表格的表頭——「南翼樓整修工程材料更換申請」。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任轉過頭。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了許星棠在基座旁邊。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "你在拍什麼？", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音急促。帶著掩飾的緊張。他的步伐比正常快了半拍，走過來的時候手從背後抽出來——手指在發抖。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "拆展紀錄。文檔組的。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把相機螢幕翻過來給他看。螢幕上是剛才拍的展板拆除畫面——她拍了幾張正常的拆展照，夾在基座照片中間。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "基座不用拍。這些會統一處理。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手伸向相機。沒有碰到。但那個動作——和第六章一模一樣。手指緊捏到指節發白。像在藏見不得光的東西。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "好。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她退了一步。相機收回胸前。臉上什麼都沒有。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任盯著她看了兩秒。然後轉向基座，蹲下來檢查暗槽的封條。他的手指在金屬邊緣上摸了一遍——確認沒有被打開。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道許星棠已經拍了。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從側門方向走回來。他的手電筒別回腰間，臉上帶著一絲不耐煩。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "側門坡度沒問題。輪組可以走。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Staff, character: "行政組人員", dialogue: "那就按這條線搬。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "行政組人員回到基座旁邊。他的視線重新釘在基座上。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠已經退回暫存區。她把相機掛回脖子上，低頭整理器材箱裡的東西。動作很平。像什麼都沒發生過。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）拍到了嗎。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看不見許星棠的相機螢幕。只能從她的肢體語言判斷。她的肩膀沒有繃緊。呼吸沒有變。手指沒有在背帶上收緊。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有慌。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但林主任回來得太快了。行政組那個人只離開了兩步。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她可能只拍到了一部分。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任站起來。他看了韓越一眼，又看了許星棠一眼。然後拿出手機，撥了一個號碼，走到展板後面。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言聽不見他說什麼。但他認得那個動作——第六章、第七章，林主任每次回報邵叔，都是這個姿勢。背對人。手機貼著耳朵。肩膀縮起來。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在打給邵叔。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）沒關係。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）讓他打。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他回報的內容只會讓邵叔更放心——有人靠近基座，但被攔住了。底板沒有被動。資料還在可控範圍。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔不會因為這個加強基座的防護。他只會覺得林主任在做事。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任收起手機。走回基座旁邊。他的臉色比剛才更難看了——不是憤怒，是恐懼。那種長期被威脅的人，每一次電話響起都會更瘦一圈的恐懼。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越經過顧言藏身的展板堆。他沒有停步。沒有轉頭。但他的右手在身側做了一個很小的動作——拇指和食指捏了一下，然後鬆開。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗號。意思是：拿到了。但不多。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）部分資料。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）底板暗槽。付款紀錄。材料更換單。林主任動過底板的痕跡。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不一定全拍到了。但只要有部分——加上父親的加密檔——就能互相補強。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從展板堆後面退出來。腳步很輕。走廊上的應急燈把他的影子拉得很長。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館裡，拆展繼續。工作人員在封箱。林主任站在基座旁邊，手背在身後，手指在抖。行政組人員拿著板夾，像一根釘子釘在基座旁邊。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠最後一個離開暫存區。她背著器材箱，走過基座的時候，沒有看它一眼。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她的右手一直按在相機的快門鍵上。不是要拍。是確認。確認相機還在。確認剛才拍的東西還在。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:45。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨更大了。校史館的拱形窗上全是水。玻璃後面的路燈變成一團模糊的黃。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）基座線。部分完成。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不夠完整。但夠用。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）下一條線。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）假死道具。", background: Background.Chapter_8_Ch8_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉身。往舞台器材區方向走。", background: Background.Chapter_8_Ch8_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後，林主任的手機又響了。", background: Background.Chapter_8_Ch8_Act9_S1 },
];
